li.p:
The XQuery engine has been updated to support the changed syntax for
          maps in XQuery 3.1. The query parser will still accept the old syntax for map constructors though (map { x:= "y"}
          instead of
          map { x: "y" }
          in XQuery 3.1), so old code should run without modifications. All map module functions from XQuery 3.1 are
          available.

dd.pre:
xquery version "3.0";

import module namespace dbutil="http://exist-db.org/xquery/dbutil";

dbutil:find-by-mimetype(xs:anyURI("/db"), "application/xquery", function($resource) {
    sm:chmod($resource, "rwxr-xr-x")
}),
dbutil:scan-collections(xs:anyURI("/db"), function($collection) {
    sm:chmod($collection, "rwxr-xr-x")
})
